import java.io.*;import java.util.*;class Main{static String canonical(List<int[]> cells){List<List<int[]>> ts=new ArrayList<>();for(int i=0;i<8;i++)ts.add(new ArrayList<>());for(int[] p:cells){int x=p[0],y=p[1];int[][] vs={{x,y},{x,-y},{-x,y},{-x,-y},{y,x},{y,-x},{-y,x},{-y,-x}};for(int i=0;i<8;i++)ts.get(i).add(vs[i]);}String best=null;for(List<int[]> pts:ts){int minX=pts.get(0)[0],minY=pts.get(0)[1];for(int[] p:pts){minX=Math.min(minX,p[0]);minY=Math.min(minY,p[1]);}List<String> parts=new ArrayList<>();for(int[] p:pts)parts.add((p[0]-minX)+":"+(p[1]-minY));Collections.sort(parts);String key=String.join("|",parts);if(best==null||key.compareTo(best)<0)best=key;}return best;}static int solve(int[][] grid){int rows=grid.length,cols=grid[0].length;boolean[][] seen=new boolean[rows][cols];Set<String> shapes=new HashSet<>();int[] dr={1,-1,0,0},dc={0,0,1,-1};for(int r=0;r<rows;r++)for(int c=0;c<cols;c++)if(grid[r][c]==1&&!seen[r][c]){ArrayDeque<int[]> stack=new ArrayDeque<>();List<int[]> cells=new ArrayList<>();stack.push(new int[]{r,c});seen[r][c]=true;while(!stack.isEmpty()){int[] cur=stack.pop();int x=cur[0],y=cur[1];cells.add(new int[]{x-r,y-c});for(int k=0;k<4;k++){int nx=x+dr[k],ny=y+dc[k];if(0<=nx&&nx<rows&&0<=ny&&ny<cols&&grid[nx][ny]==1&&!seen[nx][ny]){seen[nx][ny]=true;stack.push(new int[]{nx,ny});}}}shapes.add(canonical(cells));}return shapes.size();}public static void main(String[]a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int rows=Integer.parseInt(d[idx++]),cols=Integer.parseInt(d[idx++]);int[][] grid=new int[rows][cols];for(int i=0;i<rows;i++)for(int j=0;j<cols;j++)grid[i][j]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(solve(grid));}System.out.print(out);}}
